.responsive-text-container {
  word-break: normal; /* Default, breaks only at whitespace */
  overflow-wrap: break-word; /* Breaks long words if they overflow */
  /* For even more aggressive breaking, consider: */
  /* word-break: break-all; */
  /* overflow-wrap: break-anywhere; /* Modern alternative to break-word */
}

.long-url-display {
  overflow-wrap: break-word; /* Ensures URLs break within their container */
  hyphens: auto; /* Optional: adds hyphenation when words break */
}
